import{_ as e,o as p,c as r,ah as h}from"./chunks/framework.Bg572dcY.js";const b=JSON.parse('{"title":"文档工程","description":"","frontmatter":{"title":"文档工程","order":45},"headers":[],"relativePath":"sde/workflow/quality/docs.md","filePath":"sde/workflow/quality/docs.md"}'),i={name:"sde/workflow/quality/docs.md"};function l(d,a,n,o,t,s){return p(),r("div",null,[...a[0]||(a[0]=[h('<h1 id="文档工程" tabindex="-1">文档工程 <a class="header-anchor" href="#文档工程" aria-label="Permalink to “文档工程”">​</a></h1><p>文档是软件产品的重要组成部分，良好的文档降低用户学习成本、减少支持成本、提高团队协作效率。文档工程是系统化地创建、维护和改进文档的实践，将文档视为一等公民，与代码同等重视。</p><h2 id="文档类型" tabindex="-1">文档类型 <a class="header-anchor" href="#文档类型" aria-label="Permalink to “文档类型”">​</a></h2><h3 id="用户文档" tabindex="-1">用户文档 <a class="header-anchor" href="#用户文档" aria-label="Permalink to “用户文档”">​</a></h3><p>用户手册：介绍产品的使用方法，面向最终用户。</p><p>快速开始：帮助用户快速上手，通常是 5-10 分钟的入门教程。</p><p>API 文档：描述 API 的使用方法，包括请求响应示例。</p><p>故障排查：列出常见问题和解决方案。</p><h3 id="开发文档" tabindex="-1">开发文档 <a class="header-anchor" href="#开发文档" aria-label="Permalink to “开发文档”">​</a></h3><p>架构文档：描述系统架构、设计决策、技术选型。</p><p>开发指南：指导开发者如何搭建开发环境、构建项目、运行测试。</p><p>代码规范：编码风格、命名规范、最佳实践。</p><p>部署文档：描述如何部署应用，包括环境要求、配置说明。</p><h3 id="运维文档" tabindex="-1">运维文档 <a class="header-anchor" href="#运维文档" aria-label="Permalink to “运维文档”">​</a></h3><p>监控手册：监控指标含义、告警处理流程。</p><p>应急预案：常见故障的处理步骤，联系人信息。</p><p>变更记录：系统变更的历史记录，便于问题追溯。</p><h2 id="api-文档" tabindex="-1">API 文档 <a class="header-anchor" href="#api-文档" aria-label="Permalink to “API 文档”">​</a></h2><h3 id="openapi-规范" tabindex="-1">OpenAPI 规范 <a class="header-anchor" href="#openapi-规范" aria-label="Permalink to “OpenAPI 规范”">​</a></h3><p>OpenAPI（原 Swagger）是 RESTful API 的文档标准。</p><p>信息描述：API 基本信息（标题、版本、描述）。</p><p>路径定义：每个端点的路径、方法、参数、响应。</p><p>数据模型：请求和响应的数据结构。</p><p>安全定义：认证方式（API Key、OAuth2）。</p><h3 id="文档生成" tabindex="-1">文档生成 <a class="header-anchor" href="#文档生成" aria-label="Permalink to “文档生成”">​</a></h3><p>Swagger UI：根据 OpenAPI 规范自动生成交互式文档。</p><p>Redoc：生成美观的静态文档页面。</p><p>代码注释：从代码注释自动生成文档（如 Java Javadoc、Go Doc）。</p><h3 id="文档示例" tabindex="-1">文档示例 <a class="header-anchor" href="#文档示例" aria-label="Permalink to “文档示例”">​</a></h3><p>清晰的示例是 API 文档的关键。</p><p>请求示例：展示真实的请求格式，包括 headers、body。</p><p>响应示例：展示成功和失败的响应。</p><p>错误码：列出所有可能的错误码和含义。</p><p>使用场景：展示 API 的典型使用场景。</p><h2 id="文档工具" tabindex="-1">文档工具 <a class="header-anchor" href="#文档工具" aria-label="Permalink to “文档工具”">​</a></h2><h3 id="markdown" tabindex="-1">Markdown <a class="header-anchor" href="#markdown" aria-label="Permalink to “Markdown”">​</a></h3><p>Markdown 是轻量级标记语言，易于编写和阅读。</p><p>语法简单：基本语法可以在几分钟内学会。</p><p>广泛支持：几乎所有文档平台都支持 Markdown。</p><p>版本控制：纯文本格式，适合 Git 管理。</p><h3 id="静态站点生成器" tabindex="-1">静态站点生成器 <a class="header-anchor" href="#静态站点生成器" aria-label="Permalink to “静态站点生成器”">​</a></h3><p>VitePress：基于 Vite 的文档生成器，本站使用。</p><p>Docusaurus：Facebook 开源的文档平台，支持多版本。</p><p>Hugo：Go 编写的快速静态站点生成器。</p><p>GitBook：商业文档平台，提供托管服务。</p><h3 id="api-文档工具" tabindex="-1">API 文档工具 <a class="header-anchor" href="#api-文档工具" aria-label="Permalink to “API 文档工具”">​</a></h3><p>Swagger：OpenAPI 规范的实现工具。</p><p>Postman：API 开发和文档平台。</p><p>Apifox：国产 API 管理工具，支持文档、Mock、测试。</p><h3 id="架构文档工具" tabindex="-1">架构文档工具 <a class="header-anchor" href="#架构文档工具" aria-label="Permalink to “架构文档工具”">​</a></h3><p>Mermaid：文本到图表的工具，支持流程图、时序图、状态图。</p><p>PlantUML：UML 图表工具，支持类图、时序图、组件图。</p><p>C4 Model：架构图描述语言，关注上下文、容器、组件、代码。</p><h2 id="文档最佳实践" tabindex="-1">文档最佳实践 <a class="header-anchor" href="#文档最佳实践" aria-label="Permalink to “文档最佳实践”">​</a></h2><h3 id="文档即代码" tabindex="-1">文档即代码 <a class="header-anchor" href="#文档即代码" aria-label="Permalink to “文档即代码”">​</a></h3><p>版本控制：文档与代码同仓库管理，版本同步。</p><p>审查流程：文档变更与代码变更一起审查。</p><p>自动化构建：文档作为构建流程的一部分，自动生成和部署。</p><h3 id="文档结构" tabindex="-1">文档结构 <a class="header-anchor" href="#文档结构" aria-label="Permalink to “文档结构”">​</a></h3><p>层次清晰：文档有明确的层次结构，便于导航。</p><p>搜索友好：提供搜索功能，快速定位内容。</p><p>多级导航：侧边栏提供多级导航，展示文档结构。</p><h3 id="文档内容" tabindex="-1">文档内容 <a class="header-anchor" href="#文档内容" aria-label="Permalink to “文档内容”">​</a></h3><p>面向读者：根据读者背景调整内容深度。</p><p>图文并茂：使用图表、截图辅助说明。</p><p>示例驱动：提供可运行的示例，帮助读者理解。</p><p>保持更新：代码变更时同步更新文档，避免文档过时。</p><h3 id="文档风格" tabindex="-1">文档风格 <a class="header-anchor" href="#文档风格" aria-label="Permalink to “文档风格”">​</a></h3><p>简洁明了：用简单的语言表达复杂的概念，避免术语堆砌。</p><p>主动语态：使用主动语态，如&quot;点击按钮&quot;而非&quot;按钮被点击&quot;。</p><p>一致性：术语翻译、格式风格保持一致。</p><h3 id="交互式文档" tabindex="-1">交互式文档 <a class="header-anchor" href="#交互式文档" aria-label="Permalink to “交互式文档”">​</a></h3><p>可运行示例：在文档中嵌入可运行的代码片段。</p><p>交互式 API：文档中的 API 可以直接调用。</p><p>实时预览：修改代码实时预览效果。</p><h2 id="文档维护" tabindex="-1">文档维护 <a class="header-anchor" href="#文档维护" aria-label="Permalink to “文档维护”">​</a></h2><h3 id="文档生命周期" tabindex="-1">文档生命周期 <a class="header-anchor" href="#文档生命周期" aria-label="Permalink to “文档生命周期”">​</a></h3><p>创建：新功能开发时同步创建文档。</p><p>更新：代码变更时更新相关文档。</p><p>废弃：功能移除时标记文档为废弃。</p><p>归档：旧版本文档归档保留，便于参考。</p><h3 id="文档审查" tabindex="-1">文档审查 <a class="header-anchor" href="#文档审查" aria-label="Permalink to “文档审查”">​</a></h3><p>技术审查：确保文档内容准确、完整。</p><p>语言审查：确保文档语言通顺、易懂。</p><p>用户反馈：收集用户反馈，持续改进文档。</p><h3 id="文档指标" tabindex="-1">文档指标 <a class="header-anchor" href="#文档指标" aria-label="Permalink to “文档指标”">​</a></h3><p>页面浏览：了解哪些文档最常被访问。</p><p>停留时间：了解文档是否有帮助。</p><p>搜索关键词：了解用户在寻找什么。</p><p>跳出率：了解文档是否满足用户需求。</p><h2 id="文档文化" tabindex="-1">文档文化 <a class="header-anchor" href="#文档文化" aria-label="Permalink to “文档文化”">​</a></h2><h3 id="文档优先" tabindex="-1">文档优先 <a class="header-anchor" href="#文档优先" aria-label="Permalink to “文档优先”">​</a></h3><p>先写文档：开发功能前先写文档，明确需求。</p><p>文档驱动：文档是设计的一部分，而非开发后的补充。</p><p>文档评审：文档与代码同等重视，需要评审才能合并。</p><h3 id="知识共享" tabindex="-1">知识共享 <a class="header-anchor" href="#知识共享" aria-label="Permalink to “知识共享”">​</a></h3><p>文档分享：定期分享文档编写经验。</p><p>文档培训：培训团队成员如何编写高质量文档。</p><p>文档激励：认可和奖励文档贡献者。</p><h3 id="持续改进" tabindex="-1">持续改进 <a class="header-anchor" href="#持续改进" aria-label="Permalink to “持续改进”">​</a></h3><p>定期审查：定期审查文档，更新过时内容。</p><p>用户调研：了解用户文档需求，改进文档结构。</p><p>工具优化：持续优化文档工具，提高编写效率。</p><p>文档工程是软件工程的重要组成部分，良好的文档降低沟通成本、提高团队效率、改善用户体验。建立文档优先的文化，将文档视为一等公民，是构建高质量软件产品的关键。</p>',104)])])}const P=e(i,[["render",l]]);export{b as __pageData,P as default};
